function greet() {
  console.log("أهلًا وسهلًا!");
}

greet();  // استدعاء أول
greet();  // ثانٍ — نفس الكود دون تكرار كتابته

function welcome(name = "زائر") {
  console.log("مرحبًا يا " + name);
}

welcome("سارة");  // مرحبًا يا سارة
welcome();          // مرحبًا يا زائر

function add(a, b) {
  return a + b;
}

const result = add(7, 5);
console.log(result);            // 12
console.log(add(2, 3) * 10);   // 50 — الناتج قيمة نستخدمها

const appName = "منصتنا";  // عام

function show() {
  const secret = "محلي";    // محلي
  console.log(appName, "-", secret); // يرى الاثنين
}
show();
try { console.log(secret); } catch (e) { console.log("secret غير مرئي خارج الدالة ✓"); }
